content:
/* WildKeys — toned-down neobrutalist, warm & premium */

:root {
  --bg: #e6ded2;
  --bg-deep: #d9d0c2;
  --surface: #f0e9df;
  --surface-2: #f7f1e8;
  --ink: #2f2a26;
  --ink-soft: #5c534c;
  --ink-mute: #8a7f74;
  --line: #3a332e;
  --shadow: rgba(196, 183, 166, 0.5);
  --shadow-deep: rgba(168, 152, 132, 0.5);
  --accent: #c4785a;
  --accent-2: #6f8f7a;
  --accent-3: #b88a4a;
  --danger: #b45a4e;
  --ok: #5d8a6a;
  --radius: 14px;
  --radius-sm: 10px;
  --border: 2.5px solid var(--line);
  --font: "Outfit", "Segoe UI", system-ui, sans-serif;
  --mono: "JetBrains Mono", "Cascadia Mono", Consolas, ui-monospace, monospace;
  --ease: cubic-bezier(0.2, 0.8, 0.2, 1);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  height: 100%;
  background: var(--bg);
  color: var(--ink);
  font-family: var(--font);
  -webkit-font-smoothing: antialiased;
  overflow: hidden;
}

body {
  background:
    radial-gradient(1200px 600px at 10% -10%, rgba(196, 120, 90, 0.12), transparent 55%),
    radial-gradient(900px 500px at 100% 0%, rgba(111, 143, 122, 0.10), transparent 50%),
    linear-gradient(165deg, #ebe3d7 0%, #e0d6c8 48%, #d9d0c2 100%);
}

button,
input,
textarea {
  font: inherit;
  color: inherit;
}

button {
  cursor: pointer;
  border: none;
  background: none;
}

.app {
  height: 100%;
  display: grid;
  grid-template-rows: auto 1fr;
  gap: 0;
  margin: 0;
  max-width: none;
  overflow: hidden;
  border: 1.5px solid rgba(58, 51, 46, 0.18);
}

.app-body {
  min-height: 0;
  display: flex;
  flex-direction: column;
  padding: 14px 22px 16px;
  overflow: hidden;
}

.app-body .layout {
  flex: 1;
  min-height: 0;
}

/* ── Custom title bar (frameless) ────────────────────── */

.titlebar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  height: 52px;
  min-height: 52px;
  padding: 0 0 0 14px;
  background: rgba(240, 233, 223, 0.72);
  border-bottom: 2px solid rgba(58, 51, 46, 0.12);
  user-select: none;
  flex-shrink: 0;
  cursor: default;
}

.titlebar.is-dragging {
  cursor: grabbing;
}

.titlebar-drag {
  flex: 1;
  min-width: 0;
  height: 100%;
  display: flex;
  align-items: center;
}

.titlebar-right {
  display: flex;
  align-items: center;
  gap: 10px;
  height: 100%;
  flex-shrink: 0;
}

.brand {
  display: flex;
  align-items: center;
  gap: 10px;
}

.mark {
  width: 36px;
  height: 36px;
  display: grid;
  place-items: center;
  flex-shrink: 0;
  background: transparent;
  border: none;
  box-shadow: none;
  padding: 0;
}

.mark-logo {
  width: 36px;
  height: 36px;
  object-fit: contain;
  display: block;
  image-rendering: auto;
  user-select: none;
  pointer-events: none;
}

.brand-text {
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: 2px;
  min-height: 0;
}

.brand-text h1 {
  margin: 0;
  font-size: 1.15rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1;
}

.brand-byline {
  margin: 0;
  font-size: 0.72rem;
  font-weight: 500;
  letter-spacing: 0.01em;
  line-height: 1.1;
  color: rgba(58, 51, 46, 0.55);
}

.win-controls {
  display: flex;
  align-items: center;
  gap: 8px;
  height: 100%;
  padding-right: 10px;
}

/* Same chrome as modal close — shared .modal-close look */
.win-chrome.modal-close {
  width: 28px;
  height: 28px;
  font-size: 0;
  line-height: 0;
}

.win-chrome.win-close:hover {
  background: #c75b4e;
  border-color: #5c2e28;
}

.win-chrome.win-close:hover .chrome-icon {
  filter: brightness(0) invert(1);
}

.win-chrome.win-close:active {
  background: #a84a3f;
}

.win-chrome.win-close:active .chrome-icon {
  filter: brightness(0) invert(1);
}

/* Toggle */

.toggle {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  user-select: none;
  cursor: pointer;
  padding: 6px 10px 6px 8px;
  border-radius: 999px;
  border: var(--border);
  background: var(--surface-2);
  box-shadow: 3px 3px 0 var(--shadow);
}

.toggle input {
  position: absolute;
  opacity: 0;
  pointer-events: none;
}

.toggle-track {
  width: 42px;
  height: 24px;
  border-radius: 999px;
  border: 2px solid var(--line);
  background: var(--bg-deep);
  position: relative;
  transition: background 0.2s var(--ease);
}

.toggle-thumb {
  position: absolute;
  top: 2px;
  left: 2px;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: var(--surface-2);
  border: 2px solid var(--line);
  transition: transform 0.2s var(--ease), background 0.2s var(--ease);
}

.toggle input:checked + .toggle-track {
  background: #c9dccf;
}

.toggle input:checked + .toggle-track .toggle-thumb {
  transform: translateX(18px);
  background: var(--ok);
  border-color: #3d5c46;
}

.toggle-label {
  font-size: 0.82rem;
  font-weight: 600;
  min-width: 3.2rem;
}

/* ── Layout ──────────────────────────────────────────── */

.layout {
  display: grid;
  /* Left pane ~200px narrower than a 50/50 split; right takes the rest */
  grid-template-columns: minmax(200px, calc((100% - 16px) / 2 - 100px)) minmax(280px, 1fr);
  gap: 16px;
  min-height: 0;
}

.deck-panel,
.editor-panel {
  min-height: 0;
  border: var(--border);
  border-radius: var(--radius);
  background: var(--surface);
  box-shadow: 5px 5px 0 var(--shadow);
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.panel-head {
  box-sizing: border-box;
  height: 52px;
  min-height: 52px;
  max-height: 52px;
  padding: 0 14px;
  border-bottom: 2px solid rgba(58, 51, 46, 0.12);
  flex-shrink: 0;
  display: flex;
  align-items: center; /* vertical center */
  justify-content: flex-start;
}

.panel-head.deck-head {
  justify-content: space-between;
  gap: 12px;
}

.panel-head.deck-head .toggle {
  flex-shrink: 0;
}

.panel-head h2 {
  margin: 0;
  padding: 0;
  font-size: 1.15rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1;
  display: flex;
  align-items: center;
  min-width: 0;
}

/* ── Deck cards ──────────────────────────────────────── */

.deck {
  flex: 1;
  min-height: 0;
  padding: 8px 10px;
  display: flex;
  flex-direction: column;
  gap: 5px;
  overflow: hidden; /* 10 rows must fit — no scrollbar */
  justify-content: center;
}

.deck-foot {
  flex-shrink: 0;
  margin: 0;
  padding: 10px 14px 12px;
  border-top: 2px solid rgba(58, 51, 46, 0.12);
  font-size: 0.84rem;
  font-weight: 500;
  color: var(--ink-soft);
  line-height: 1.4;
}

.deck-row {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 8px;
  width: 100%;
  min-width: 0;
  flex: 0 0 auto;
  height: 40px;
}

.deck-row.key-off .card,
.deck-row.key-off .key-combo {
  opacity: 0.62;
}

.card {
  position: relative;
  text-align: left;
  border: var(--border);
  border-radius: 8px;
  background: var(--surface-2);
  box-shadow: 2px 2px 0 var(--shadow);
  padding: 0 10px;
  height: 100%;
  transition: background 0.15s var(--ease), outline-color 0.15s var(--ease), opacity 0.15s var(--ease);
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: flex-start;
  gap: 10px;
  flex: 1;
  min-width: 0;
  min-height: 0;
  cursor: pointer;
  font: inherit;
  color: inherit;
  outline: 2px solid transparent;
  outline-offset: 0;
}

.card:hover {
  background: #ebe3d6;
}

.card:active {
  background: #e3d9c9;
}

.card.active {
  background: #faf6ef;
  outline-color: rgba(196, 120, 90, 0.4);
}

.card.active:hover {
  background: #f3ebe0;
}

.key-combo {
  display: flex;
  align-items: center;
  flex-wrap: nowrap;
  gap: 5px;
  flex-shrink: 0;
  height: 100%;
}

.row-toggle {
  flex-shrink: 0;
  padding: 3px 5px;
  box-shadow: 2px 2px 0 var(--shadow);
}

.row-toggle.is-locked {
  opacity: 0.45;
  cursor: default;
  box-shadow: 1px 1px 0 var(--shadow);
}

.row-toggle.is-locked input:disabled {
  cursor: default;
}

.toggle-sm .toggle-track {
  width: 32px;
  height: 18px;
}

.toggle-sm .toggle-thumb {
  width: 10px;
  height: 10px;
  top: 2px;
  left: 2px;
}

.toggle-sm input:checked + .toggle-track .toggle-thumb {
  transform: translateX(14px);
}

.key-badge {
  height: 22px;
  min-width: 22px;
  padding: 0 7px;
  border-radius: 7px;
  border: 2px solid var(--line);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font);
  font-weight: 600;
  font-size: 0.62rem;
  letter-spacing: 0.02em;
  text-transform: uppercase;
  text-align: center;
  background: var(--bg);
  line-height: 1;
  box-shadow: 1px 1px 0 var(--shadow);
}

.key-badge.mod {
  color: var(--ink);
}

.key-badge.letter {
  width: 26px;
  min-width: 26px;
  max-width: 26px;
  padding: 0;
  box-sizing: border-box;
  color: var(--ink);
}

/*
 * Per-shortcut badge tint — same for Ctrl/Alt/letter on a row.
 * Hues follow list meaning (soft pastels that fit the sand UI):
 *   Q shot      warm clay (framing / camera body)
 *   W angle     cool steel (lens / geometry)
 *   R lighting  golden amber (light)
 *   T pose      blush rose (body / gesture)
 *   Y backdrop  sage green (environment)
 *   U art style soft violet (creative)
 *   I hair      warm cocoa (hair)
 *   D face      coral peach (expression)
 *   G wardrobe  denim mist (cloth)
 *   K details   champagne (jewelry / polish)
 */
.deck-row[data-key="q"] .key-badge,
.editor-keys[data-key="q"] .key-badge { background: #e8cfc3; } /* Shot type */
.deck-row[data-key="w"] .key-badge,
.editor-keys[data-key="w"] .key-badge { background: #cfdce8; } /* Camera angle */
.deck-row[data-key="r"] .key-badge,
.editor-keys[data-key="r"] .key-badge { background: #efdfb6; } /* Lighting */
.deck-row[data-key="t"] .key-badge,
.editor-keys[data-key="t"] .key-badge { background: #ebcfd6; } /* Pose */
.deck-row[data-key="y"] .key-badge,
.editor-keys[data-key="y"] .key-badge { background: #d2e3d4; } /* Background */
.deck-row[data-key="u"] .key-badge,
.editor-keys[data-key="u"] .key-badge { background: #dcd3eb; } /* Art style */
.deck-row[data-key="i"] .key-badge,
.editor-keys[data-key="i"] .key-badge { background: #e3d2c0; } /* Hair */
.deck-row[data-key="d"] .key-badge,
.editor-keys[data-key="d"] .key-badge { background: #f0d0c8; } /* Expression */
.deck-row[data-key="g"] .key-badge,
.editor-keys[data-key="g"] .key-badge { background: #d0dbe6; } /* Wardrobe */
.deck-row[data-key="k"] .key-badge,
.editor-keys[data-key="k"] .key-badge { background: #e8dfc0; } /* Details */

.card-label {
  font-weight: 650;
  font-size: 0.86rem;
  letter-spacing: -0.02em;
  line-height: 1.1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  text-align: left;
  min-width: 0;
  flex: 1;
}

/* ── Editor ──────────────────────────────────────────── */

.editor-panel {
  padding: 0 0 14px;
}

.editor-head {
  width: 100%;
  display: flex;
  justify-content: space-between;
  align-items: center; /* vertical center title + shortcut */
  gap: 12px;
}

.editor-head > div {
  min-width: 0;
  height: 100%;
  display: flex;
  align-items: center;
}

.editor-head h2 {
  margin: 0;
  padding: 0;
  font-size: 1.15rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  display: flex;
  align-items: center;
}

.editor-keys {
  flex-shrink: 0;
  height: auto;
  align-self: center;
}

.field {
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding: 12px 18px 0;
  font-size: 0.78rem;
  font-weight: 600;
  color: var(--ink-soft);
}

.field.grow {
  flex: 1;
  min-height: 0;
}

.field-label {
  font-size: 0.95rem;
  font-weight: 700;
  letter-spacing: -0.02em;
  color: var(--ink);
  padding-left: 12px;
}

.field-row {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
}

.count {
  font-family: var(--mono);
  font-size: 0.72rem;
  font-weight: 600;
  color: var(--ink-mute);
}

.field input {
  width: 100%;
  border: var(--border);
  border-radius: var(--radius-sm);
  background: var(--surface-2);
  padding: 11px 12px;
  outline: none;
  box-shadow: inset 0 0 0 0 transparent;
  transition: box-shadow 0.15s var(--ease), border-color 0.15s var(--ease);
  font-size: 1rem;
  font-weight: 500;
}

.field input:focus {
  box-shadow: 0 0 0 3px rgba(196, 120, 90, 0.22);
}

.field input:disabled {
  opacity: 0.55;
  cursor: not-allowed;
}

.lines-editor {
  position: relative;
  flex: 1;
  min-height: 180px;
  display: flex;
  border: var(--border);
  border-radius: var(--radius-sm);
  background: var(--surface-2);
  overflow: hidden;
  transition: box-shadow 0.15s var(--ease);
}

.lines-main {
  position: relative;
  flex: 1;
  min-width: 0;
  min-height: 0;
  display: flex;
  overflow: hidden;
}

.save-success-gif {
  --sb-right: 0px;
  --sb-bottom: 0px;
  position: absolute;
  /*
    Layer: text (textarea) < GIF < scrollbars.
    Insets are set in JS only when a scrollbar is actually present;
    otherwise the GIF sits flush on the bottom-right borders.
  */
  right: var(--sb-right);
  bottom: var(--sb-bottom);
  top: auto;
  transform: none;
  width: auto;
  height: 300px;
  max-height: calc(100% - var(--sb-bottom));
  object-fit: contain;
  object-position: bottom right;
  pointer-events: none;
  z-index: 2;
}

.save-success-gif[hidden] {
  display: none !important;
}

.lines-editor:focus-within {
  box-shadow: 0 0 0 3px rgba(196, 120, 90, 0.22);
}

.lines-editor.is-disabled {
  opacity: 0.55;
}

.line-gutter {
  --gutter-pad-x: 8px;
  --digits: 1;
  position: relative;
  z-index: 3;
  flex: 0 0 auto;
  /* Digit block width + equal padding on both sides */
  width: calc(var(--digits) * 1ch + (2 * var(--gutter-pad-x)));
  box-sizing: border-box;
  padding: 11px var(--gutter-pad-x);
  margin: 0;
  border: none;
  border-right: 2px solid rgba(58, 51, 46, 0.12);
  background: var(--bg-deep);
  color: var(--ink-mute);
  font-family: var(--mono);
  font-size: 0.72rem;
  font-weight: 600;
  font-variant-numeric: tabular-nums;
  /* Match textarea row height: 0.9rem * 1.5 */
  line-height: 1.35rem;
  text-align: right;
  white-space: pre;
  overflow: hidden;
  user-select: none;
  tab-size: 2;
}

.lines-editor textarea {
  position: relative;
  z-index: 1;
  flex: 1;
  min-width: 0;
  min-height: 0;
  width: 100%;
  height: 100%;
  border: none;
  border-radius: 0;
  background: transparent;
  padding: 11px 12px;
  outline: none;
  resize: none;
  line-height: 1.35rem;
  font-family: var(--font);
  font-size: 0.9rem;
  font-weight: 450;
  color: var(--ink);
  white-space: pre;
  overflow: auto;
  tab-size: 2;
}

.lines-editor textarea:disabled {
  cursor: not-allowed;
}

.editor-actions {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  padding: 14px 18px 0;
}

.btn {
  border: var(--border);
  border-radius: 10px;
  padding: 10px 16px;
  font-weight: 650;
  font-size: 0.84rem;
  letter-spacing: -0.01em;
  box-shadow: 3px 3px 0 var(--shadow);
  transition: background 0.15s var(--ease), filter 0.15s var(--ease);
}

.btn:hover:not(:disabled):not(.is-saving) {
  filter: brightness(0.97);
}

.btn:active:not(:disabled):not(.is-saving) {
  filter: brightness(0.93);
}

.btn:disabled {
  opacity: 0.45;
  cursor: not-allowed;
  box-shadow: 2px 2px 0 var(--shadow);
}

.btn.primary {
  background: #d4a08c;
  color: var(--ink);
  transition:
    background 0.15s var(--ease),
    filter 0.15s var(--ease),
    color 300ms ease;
}

.btn.primary:hover:not(:disabled):not(.is-saving) {
  background: #c9917a;
}

/* Save in progress: only the label color mutes (not the full button) */
.btn.primary.is-saving {
  color: rgba(47, 42, 38, 0.38);
  cursor: default;
}

.btn.ghost {
  background: var(--surface-2);
}

.toast {
  margin: 12px 18px 0;
  padding: 10px 12px;
  border-radius: 10px;
  border: 2px solid var(--line);
  background: #e5efe6;
  font-size: 0.78rem;
  font-weight: 500;
  color: var(--ink-soft);
  box-shadow: 2px 2px 0 var(--shadow);
  animation: toast-in 0.25s var(--ease);
}

.toast.error {
  background: #f0ddd8;
}

@keyframes toast-in {
  from {
    opacity: 0;
    transform: translateY(4px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* ── Preview modal ───────────────────────────────────── */

.modal-root {
  position: fixed;
  inset: 0;
  z-index: 1000;
  display: grid;
  place-items: center;
  padding: 24px;
}

.modal-root[hidden] {
  display: none !important;
}

.modal-loading {
  z-index: 2000;
}

.modal-loading .modal-backdrop {
  cursor: default;
  background: rgba(55, 55, 58, 0.45);
}

.loading-card {
  min-width: 220px;
  pointer-events: none;
}

.loading-body {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 28px 32px 26px;
  text-align: center;
}

.loading-logo {
  width: 56px;
  height: 56px;
  object-fit: contain;
  display: block;
  user-select: none;
  pointer-events: none;
}

.loading-title {
  margin: 0;
  font-size: 1.15rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1;
  color: var(--ink);
}

.loading-sub {
  margin: 0;
  font-size: 0.84rem;
  font-weight: 500;
  color: var(--ink-soft);
  line-height: 1.3;
}

.modal-backdrop {
  position: absolute;
  inset: 0;
  background: rgba(55, 55, 58, 0.4);
  cursor: pointer;
}

.modal {
  position: relative;
  z-index: 1;
  width: min(420px, 100%);
  border: var(--border);
  border-radius: var(--radius);
  background: var(--surface);
  box-shadow: 6px 6px 0 rgba(154, 149, 144, 0.5);
  display: flex;
  flex-direction: column;
  max-height: min(90vh, 480px);
  animation: toast-in 0.2s var(--ease);
}

.modal-head {
  box-sizing: border-box;
  height: 52px;
  min-height: 52px;
  max-height: 52px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 0 14px;
  border-bottom: 2px solid rgba(58, 51, 46, 0.12);
  flex-shrink: 0;
}

.modal-head h2 {
  margin: 0;
  padding: 0;
  font-size: 1.15rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1;
  display: flex;
  align-items: center;
  height: 100%;
}

.modal-close {
  width: 28px;
  height: 28px;
  border-radius: 8px;
  border: 2px solid var(--line);
  background: var(--surface-2);
  box-shadow: 2px 2px 0 var(--shadow);
  font-size: 0;
  line-height: 0;
  color: var(--ink);
  display: grid;
  place-items: center;
  padding: 0;
  flex-shrink: 0;
  transition: background 0.15s var(--ease);
}

.modal-close:hover {
  background: #ebe3d6;
}

.chrome-icon {
  width: 10px !important;
  height: 10px !important;
  max-width: 10px !important;
  max-height: 10px !important;
  min-width: 0 !important;
  min-height: 0 !important;
  display: block;
  object-fit: contain;
  object-position: center;
  pointer-events: none;
  user-select: none;
  flex-shrink: 0;
}

.modal-close .chrome-icon {
  width: 10px !important;
  height: 10px !important;
}

.modal-body {
  padding: 14px 16px;
  overflow: auto;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.modal-lead {
  margin: 0;
  font-size: 0.84rem;
  font-weight: 500;
  color: var(--ink-soft);
  line-height: 1.35;
}

.modal-textarea {
  width: 100%;
  border: var(--border);
  border-radius: var(--radius-sm);
  background: var(--surface-2);
  padding: 12px;
  outline: none;
  resize: vertical;
  min-height: 110px;
  font-family: var(--font);
  font-size: 0.95rem;
  font-weight: 500;
  line-height: 1.45;
  color: var(--ink);
}

.modal-textarea:focus {
  box-shadow: 0 0 0 3px rgba(196, 120, 90, 0.22);
}

.modal-actions {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  padding: 12px 16px 16px;
  border-top: 2px solid rgba(58, 51, 46, 0.12);
}

.modal-sm {
  width: min(400px, 100%);
}



/* Scrollbars */
.deck::-webkit-scrollbar {
  width: 10px;
}
.deck::-webkit-scrollbar-thumb {
  background: #a8a49e;
  border-radius: 999px;
  border: 2px solid transparent;
  background-clip: padding-box;
}
.deck::-webkit-scrollbar-track {
  background: var(--bg-deep);
  border-radius: 999px;
}

/* List lines field — wider scrollbar + clickable cursor */
.lines-editor textarea {
  scrollbar-width: auto; /* Firefox */
  scrollbar-color: #a8a49e var(--bg-deep);
}

.lines-editor textarea::-webkit-scrollbar {
  width: 14px;
}

.lines-editor textarea::-webkit-scrollbar-track {
  background: var(--bg-deep);
  border-radius: 999px;
  cursor: pointer;
}

.lines-editor textarea::-webkit-scrollbar-thumb {
  background: #a8a49e;
  border-radius: 999px;
  border: 3px solid var(--bg-deep);
  background-clip: padding-box;
  cursor: pointer;
  min-height: 28px;
}

.lines-editor textarea::-webkit-scrollbar-thumb:hover {
  background: #949089;
  border: 3px solid var(--bg-deep);
  background-clip: padding-box;
  cursor: pointer;
}

.lines-editor textarea::-webkit-scrollbar-thumb:active {
  background: #7f7b75;
  cursor: grabbing;
}

.lines-editor textarea::-webkit-scrollbar-button {
  display: none;
  width: 0;
  height: 0;
}

@media (max-width: 920px) {
  .layout {
    grid-template-columns: 1fr;
  }
}
